#include <stdio.h>
#include <string.h>

int minPenalty(char* A, char* B, int K, int L, int x, int y) {
    int dp[K + 1][L + 1];
    for (int i = 0; i <= K; i++) {
        for (int j = 0; j <= L; j++) {
            if (i == 0) {
                if (j == 0) dp[i][j] = 0;
                else if (j == 1) dp[i][j] = x + 1;
                else dp[i][j] = y;
            } else if (j == 0) {
                dp[i][j] = i * 1 + x;
            } else {
                int replaceCost = (A[i - 1] == B[j - 1]) ? 0 : 1;
                dp[i][j] = dp[i - 1][j - 1] + replaceCost;
                int insertCost = (j == 1) ? x + 1 : y;
                dp[i][j] = (dp[i][j - 1] + insertCost < dp[i][j]) ? dp[i][j - 1] + insertCost : dp[i][j];
                int deleteCost = 1 + x;
                dp[i][j] = (dp[i - 1][j] + deleteCost < dp[i][j]) ? dp[i - 1][j] + deleteCost : dp[i][j];
            }
        }
    }
    return dp[K][L];
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int K, L;
        scanf("%d %d", &K, &L);
        char A[K + 1], B[L + 1];
        scanf("%s", A);
        scanf("%s", B);
        int x, y;
        scanf("%d %d", &x, &y);
        printf("Case %d: %d\n", t + 1, minPenalty(A, B, K, L, x, y));
    }
    return 0;
}

