import java.util.Scanner;
public class Main {
    public static int minPenalty(String A, String B, int x, int y) {
        int K = A.length(), L = B.length();
        int[][] dp = new int[K + 1][L + 1];
        for (int i = 0; i <= K; i++) {
            for (int j = 0; j <= L; j++) {
                if (i == 0) {
                    if (j == 0) dp[i][j] = 0;
                    else if (j == 1) dp[i][j] = x + 1;
                    else dp[i][j] = y;
                } else if (j == 0) {
                    dp[i][j] = i * 1 + x;
                } else {
                    int replaceCost = (A.charAt(i - 1) == B.charAt(j - 1)) ? 0 : 1;
                    dp[i][j] = dp[i - 1][j - 1] + replaceCost;
                    int insertCost = (j == 1) ? x + 1 : y;
                    dp[i][j] = (dp[i][j - 1] + insertCost < dp[i][j]) ? dp[i][j - 1] + insertCost : dp[i][j];
                    int deleteCost = 1 + x;
                    dp[i][j] = (dp[i - 1][j] + deleteCost < dp[i][j]) ? dp[i - 1][j] + deleteCost : dp[i][j];
                }
            }
        }
        return dp[K][L];
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        for (int t = 0; t < T; t++) {
            int K = scanner.nextInt(), L = scanner.nextInt();
            String A = scanner.next(), B = scanner.next();
            int x = scanner.nextInt(), y = scanner.nextInt();
            System.out.println("Case " + (t + 1) + ": " + minPenalty(A, B, x, y));
        }
    }
}

